{
  "name": "Elemental Vision",
  "description": "An immersive, offline-first periodic table explorer featuring dual-mode 3D atom visualization (Bohr & Quantum Cloud) and comprehensive chemical data."
}

export type ElementCategory = 
  | 'alkali-metal'
  | 'alkaline-earth-metal'
  | 'transition-metal'
  | 'post-transition-metal'
  | 'metalloid'
  | 'reactive-nonmetal'
  | 'noble-gas'
  | 'lanthanide'
  | 'actinide'
  | 'unknown';

export interface ElementData {
  number: number;
  symbol: string;
  name_en: string;
  name_cn: string;
  pinyin?: string;
  atomic_mass: number;
  category: ElementCategory;
  phase: 'Solid' | 'Liquid' | 'Gas' | 'Unknown';
  electron_configuration: string;
  shells: number[];
  ionization_energy?: number; // kJ/mol
  electron_affinity?: number; // kJ/mol
  electronegativity?: number; // Pauling
  atomic_radius?: number; // pm
  melting_point?: number; // Kelvin
  boiling_point?: number; // Kelvin
  density?: number; // g/cm3
  discovery_year?: string;
  discoverer?: string;
  summary_en: string;
  summary_cn: string;
  usage_en: string;
  usage_cn: string;
  hazard_en?: string;
  hazard_cn?: string;
  cpk_hex: string; // Standard CPK color for visualization
}

export type VisualMode = 'bohr' | 'cloud';
export type Language = 'en' | 'zh';

import { ElementCategory } from '../types';

export const getCategoryColor = (category: ElementCategory): string => {
  switch (category) {
    case 'alkali-metal': return '#ef4444'; // Red-500
    case 'alkaline-earth-metal': return '#f97316'; // Orange-500
    case 'transition-metal': return '#eab308'; // Yellow-500
    case 'post-transition-metal': return '#10b981'; // Emerald-500
    case 'metalloid': return '#06b6d4'; // Cyan-500
    case 'reactive-nonmetal': return '#3b82f6'; // Blue-500
    case 'noble-gas': return '#8b5cf6'; // Violet-500
    case 'lanthanide': return '#d946ef'; // Fuchsia-500
    case 'actinide': return '#f43f5e'; // Rose-500
    default: return '#64748b'; // Slate-500
  }
};

export const getCategoryGlow = (category: ElementCategory): string => {
  const color = getCategoryColor(category);
  return `0 0 15px ${color}80, 0 0 30px ${color}40`; // Neon glow effect
};

import React, { useMemo, useRef } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls, Stars, Trail } from '@react-three/drei';
import * as THREE from 'three';
import { ElementData, VisualMode } from '../types';

interface AtomProps {
  element: ElementData;
  mode: VisualMode;
  color: string;
}

const Nucleus: React.FC<{ color: string, size: number }> = ({ color, size }) => {
  return (
    <mesh>
      <sphereGeometry args={[size, 32, 32]} />
      <meshStandardMaterial 
        color={color} 
        emissive={color} 
        emissiveIntensity={0.8}
        roughness={0.2}
        metalness={0.8}
      />
      <pointLight distance={10} intensity={2} color={color} />
    </mesh>
  );
};

const Electron: React.FC<{ radius: number, speed: number, color: string, offset: number }> = ({ radius, speed, color, offset }) => {
  const ref = useRef<THREE.Mesh>(null);

  useFrame(({ clock }) => {
    if (ref.current) {
      const t = clock.getElapsedTime() * speed + offset;
      // Simple circular orbit logic on varied axes for visual effect
      ref.current.position.x = Math.cos(t) * radius;
      ref.current.position.z = Math.sin(t) * radius;
      ref.current.position.y = Math.sin(t * 0.5) * (radius * 0.3); 
    }
  });

  return (
    <group rotation={[offset, offset, 0]}> {/* Rotate the orbit plane */}
      <mesh ref={ref}>
        <sphereGeometry args={[0.15, 16, 16]} />
        <meshStandardMaterial color="#ffffff" emissive="#ffffff" emissiveIntensity={1} />
      </mesh>
      {/* Visual ring for the orbit */}
      <mesh rotation={[Math.PI / 2, 0, 0]}>
        <ringGeometry args={[radius - 0.02, radius + 0.02, 64]} />
        <meshBasicMaterial color={color} opacity={0.3} transparent side={THREE.DoubleSide} />
      </mesh>
    </group>
  );
};

const ElectronCloud: React.FC<{ count: number, color: string }> = ({ count, color }) => {
  const points = useMemo(() => {
    const p = new Float32Array(count * 3);
    for (let i = 0; i < count; i++) {
      // Gaussian distribution approx for cloud
      const u = Math.random();
      const v = Math.random();
      const theta = 2 * Math.PI * u;
      const phi = Math.acos(2 * v - 1);
      const r = Math.pow(Math.random(), 1/3) * 4 + 1; // Distribution radius

      const x = r * Math.sin(phi) * Math.cos(theta);
      const y = r * Math.sin(phi) * Math.sin(theta);
      const z = r * Math.cos(phi);

      p[i * 3] = x;
      p[i * 3 + 1] = y;
      p[i * 3 + 2] = z;
    }
    return p;
  }, [count]);

  return (
    <points>
      <bufferGeometry>
        <bufferAttribute
          attach="attributes-position"
          count={points.length / 3}
          array={points}
          itemSize={3}
        />
      </bufferGeometry>
      <pointsMaterial
        size={0.08}
        color={color}
        transparent
        opacity={0.6}
        blending={THREE.AdditiveBlending}
        depthWrite={false}
      />
    </points>
  );
};

const SceneContent: React.FC<AtomProps> = ({ element, mode, color }) => {
  const nucleusSize = Math.min(0.8 + (element.number * 0.01), 2); // Scale nucleus slightly by atomic number

  return (
    <>
      <ambientLight intensity={0.2} />
      <pointLight position={[10, 10, 10]} intensity={1} />

      {/* Nucleus */}
      <Nucleus color={color} size={nucleusSize} />

      {/* Electrons */}
      {mode === 'bohr' && (
        <group>
          {element.shells.map((count, shellIndex) => {
            const orbitRadius = nucleusSize + 1.5 + (shellIndex * 1.2);
            // Create electrons for this shell
            return Array.from({ length: count }).map((_, i) => (
              <Electron 
                key={`${shellIndex}-${i}`}
                radius={orbitRadius}
                speed={0.5 - (shellIndex * 0.05)} // Outer shells slower
                color={color}
                offset={(i / count) * Math.PI * 2}
              />
            ));
          })}
        </group>
      )}

      {/* Quantum Cloud */}
      {mode === 'cloud' && (
        <ElectronCloud count={element.number * 100 + 1000} color={color} />
      )}
    </>
  );
};

export const AtomVisualizer: React.FC<AtomProps> = (props) => {
  return (
    <div className="w-full h-full relative rounded-xl overflow-hidden shadow-2xl bg-black/40 backdrop-blur-sm border border-white/10">
      <Canvas camera={{ position: [0, 0, 12], fov: 45 }}>
        <Stars radius={100} depth={50} count={5000} factor={4} saturation={0} fade speed={1} />
        <SceneContent {...props} />
        <OrbitControls enableZoom={true} minDistance={5} maxDistance={30} autoRotate autoRotateSpeed={0.5} />
      </Canvas>

      <div className="absolute bottom-4 left-4 text-white/50 text-xs font-mono">
        {props.mode === 'bohr' ? 'BOHR MODEL (Teaching)' : 'QUANTUM CLOUD (Probability)'}
      </div>
    </div>
  );
};

import React from 'react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { ElementData, Language } from '../types';

interface ChartProps {
  element: ElementData;
  color: string;
  lang: Language;
}

export const DensityChart: React.FC<ChartProps> = ({ element, color, lang }) => {
  const data = [
    { name: lang === 'en' ? 'Water' : '水', val: 1, type: 'ref' },
    { name: element.symbol, val: element.density || 0, type: 'target' },
    { name: lang === 'en' ? 'Iron' : '铁', val: 7.87, type: 'ref' },
    { name: lang === 'en' ? 'Gold' : '金', val: 19.3, type: 'ref' },
  ];

  return (
    <div className="w-full h-40">
      <p className="text-xs text-white/60 mb-2">{lang === 'en' ? 'Density Comparison (g/cm³)' : '密度对比 (g/cm³)'}</p>
      <ResponsiveContainer width="100%" height="100%">
        <BarChart data={data} layout="vertical" margin={{ top: 5, right: 30, left: 40, bottom: 5 }}>
          <XAxis type="number" hide />
          <YAxis dataKey="name" type="category" tick={{ fill: 'white', fontSize: 12 }} width={40} />
          <Tooltip 
            contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', color: '#fff' }}
            cursor={{fill: 'rgba(255,255,255,0.05)'}}
          />
          <Bar dataKey="val" radius={[0, 4, 4, 0]}>
            {data.map((entry, index) => (
              <Cell key={`cell-${index}`} fill={entry.type === 'target' ? color : '#475569'} />
            ))}
          </Bar>
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
};

export const TempChart: React.FC<ChartProps> = ({ element, color, lang }) => {
  const mp = element.melting_point || 0;
  const bp = element.boiling_point || 0;

  // Normalize visuals slightly so bars aren't invisible for gases
  const data = [
    { name: lang === 'en' ? 'Melting' : '熔点', val: mp },
    { name: lang === 'en' ? 'Boiling' : '沸点', val: bp },
  ];

  return (
    <div className="w-full h-40 mt-4">
      <p className="text-xs text-white/60 mb-2">{lang === 'en' ? 'Phase Transition (Kelvin)' : '相变温度 (开尔文)'}</p>
      <ResponsiveContainer width="100%" height="100%">
        <BarChart data={data} margin={{ top: 5, right: 0, left: 0, bottom: 5 }}>
          <XAxis dataKey="name" tick={{ fill: 'white', fontSize: 12 }} />
          <YAxis hide />
          <Tooltip 
            contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', color: '#fff' }}
            cursor={{fill: 'rgba(255,255,255,0.05)'}}
          />
          <Bar dataKey="val" fill={color} radius={[4, 4, 0, 0]} barSize={40} />
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
};

import React from 'react';
import { ELEMENTS } from '../data/elementData';
import { ElementData, ElementCategory } from '../types';
import { getCategoryColor } from '../utils/colors';

interface PeriodicTableProps {
  onSelect: (element: ElementData) => void;
}

const PeriodicTable: React.FC<PeriodicTableProps> = ({ onSelect }) => {
  // Helper to place elements in the standard 18-column grid
  // Using a simplified map of atomic number -> grid position if CSS grid auto-flow isn't enough.
  // Standard table: 7 rows, 18 columns.
  // Lanthanides/Actinides typically below.
  // For this CSS Grid implementation, we will use classes for gaps.

  const getGridClasses = (n: number) => {
    // Row 1
    if (n === 1) return 'col-start-1 row-start-1';
    if (n === 2) return 'col-start-18 row-start-1';
    // Row 2 & 3 gaps
    if (n === 5 || n === 13) return 'col-start-13'; // Skip transition block
    // Lanthanides (57-71) and Actinides (89-103) usually separated
    // We will keep it simple: Render standard 1-118 grid, but handle the split visually?
    // Let's use a standard grid flow with manual gap handling for accurate layout.

    // Manual positions for the first few to set structure, others flow
    if (n === 5) return 'col-start-13'; 
    if (n === 13) return 'col-start-13';

    // Lanthanides/Actinides spacing
    // This is a complex layout. For a responsive web app, we might use a Flex wrap or a smart grid.
    // Let's use a simplified view where we just list them or use a predefined grid map.
    return '';
  };

  const isLanthanide = (n: number) => n >= 57 && n <= 71;
  const isActinide = (n: number) => n >= 89 && n <= 103;

  // Filter out L/A for the main table to prevent layout break, put them at bottom
  const mainTableElements = ELEMENTS.filter(e => !isLanthanide(e.number) && !isActinide(e.number));
  const lanthanides = ELEMENTS.filter(e => isLanthanide(e.number));
  const actinides = ELEMENTS.filter(e => isActinide(e.number));

  const Tile = ({ e }: { e: ElementData }) => {
    const color = getCategoryColor(e.category);

    // Layout logic for main table holes
    let style = {};
    if (e.number === 1) style = { gridColumn: 1, gridRow: 1 };
    else if (e.number === 2) style = { gridColumn: 18, gridRow: 1 };
    else if (e.number >= 3 && e.number <= 4) style = { gridRow: 2, gridColumn: e.number - 2 };
    else if (e.number >= 5 && e.number <= 10) style = { gridRow: 2, gridColumn: e.number + 8 };
    else if (e.number >= 11 && e.number <= 12) style = { gridRow: 3, gridColumn: e.number - 10 };
    else if (e.number >= 13 && e.number <= 18) style = { gridRow: 3, gridColumn: e.number + 2 };
    else if (e.number >= 19 && e.number <= 36) style = { gridRow: 4, gridColumn: e.number - 18 };
    else if (e.number >= 37 && e.number <= 54) style = { gridRow: 5, gridColumn: e.number - 36 };
    else if (e.number >= 55 && e.number <= 56) style = { gridRow: 6, gridColumn: e.number - 54 };
    // 57-71 skipped here
    else if (e.number >= 72 && e.number <= 86) style = { gridRow: 6, gridColumn: e.number - 68 }; // 72 should be col 4
    else if (e.number >= 87 && e.number <= 88) style = { gridRow: 7, gridColumn: e.number - 86 };
    // 89-103 skipped
    else if (e.number >= 104 && e.number <= 118) style = { gridRow: 7, gridColumn: e.number - 100 }; // 104 is col 4

    return (
      <button
        onClick={() => onSelect(e)}
        style={style}
        className={`
          relative w-full aspect-square flex flex-col items-center justify-center 
          border border-white/10 rounded-md transition-all duration-200 
          hover:scale-110 hover:z-10 hover:border-white/50 hover:bg-white/10
          group
        `}
      >
        <div 
          className="absolute inset-0 opacity-20 group-hover:opacity-40 transition-opacity rounded-md" 
          style={{ backgroundColor: color }}
        ></div>
        <span className="text-[0.6rem] absolute top-1 left-1 opacity-70">{e.number}</span>
        <span className="font-bold text-lg md:text-xl lg:text-2xl">{e.symbol}</span>
        <span className="text-[0.6rem] opacity-70 truncate w-full text-center px-1 hidden sm:block">
          {e.name_en}
        </span>
      </button>
    );
  };

  return (
    <div className="w-full max-w-7xl mx-auto p-4 overflow-x-auto">
      {/* Main Grid */}
      <div 
        className="grid grid-cols-18 gap-1 md:gap-2 min-w-[800px] mb-8" 
        style={{ gridTemplateRows: 'repeat(7, 1fr)' }}
      >
        {mainTableElements.map(e => <Tile key={e.number} e={e} />)}

        {/* Placeholders for Lanthanides/Actinides in main table */}
        <div style={{ gridRow: 6, gridColumn: 3 }} className="text-xs flex items-center justify-center opacity-50 border border-white/10 rounded">57-71</div>
        <div style={{ gridRow: 7, gridColumn: 3 }} className="text-xs flex items-center justify-center opacity-50 border border-white/10 rounded">89-103</div>
      </div>

      {/* F-Block */}
      <div className="grid grid-cols-18 gap-1 md:gap-2 min-w-[800px] mt-4">
         {/* Offset to align with column 4 roughly */}
         <div className="col-span-3"></div> 
         <div className="col-span-15 grid grid-cols-15 gap-1 md:gap-2">
            {lanthanides.map(e => (
              <button 
                key={e.number} 
                onClick={() => onSelect(e)}
                className="aspect-square border border-white/10 rounded hover:scale-110 transition-transform relative"
              >
                 <div className="absolute inset-0 opacity-20 bg-fuchsia-500 rounded"></div>
                 <span className="font-bold">{e.symbol}</span>
              </button>
            ))}
         </div>

         <div className="col-span-3"></div> 
         <div className="col-span-15 grid grid-cols-15 gap-1 md:gap-2 mt-1">
            {actinides.map(e => (
              <button 
                key={e.number} 
                onClick={() => onSelect(e)}
                className="aspect-square border border-white/10 rounded hover:scale-110 transition-transform relative"
              >
                 <div className="absolute inset-0 opacity-20 bg-rose-500 rounded"></div>
                 <span className="font-bold">{e.symbol}</span>
              </button>
            ))}
         </div>
      </div>
    </div>
  );
};

export default PeriodicTable;

import React, { useState } from 'react';
import { X, Layers, Activity, BookOpen, AlertTriangle, Atom } from 'lucide-react';
import { ElementData, Language, VisualMode } from '../types';
import { getCategoryColor, getCategoryGlow } from '../utils/colors';
import { AtomVisualizer } from './Atom3D';
import { DensityChart, TempChart } from './PropertyCharts';

interface DetailProps {
  element: ElementData | null;
  onClose: () => void;
  lang: Language;
}

const ElementDetail: React.FC<DetailProps> = ({ element, onClose, lang }) => {
  const [visualMode, setVisualMode] = useState<VisualMode>('bohr');

  if (!element) return null;

  const color = getCategoryColor(element.category);
  const glow = getCategoryGlow(element.category);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-0 md:p-4 bg-black/80 backdrop-blur-md animate-in fade-in duration-300">
      <div 
        className="w-full h-full md:max-w-6xl md:h-[90vh] bg-[#0f172a]/90 md:rounded-2xl border border-white/10 shadow-2xl overflow-hidden flex flex-col md:flex-row"
        style={{ boxShadow: glow }}
      >
        {/* Close Button Mobile */}
        <button 
          onClick={onClose} 
          className="absolute top-4 right-4 z-50 md:hidden p-2 bg-black/50 rounded-full"
        >
          <X className="text-white" />
        </button>

        {/* Left: 3D Visualization Area */}
        <div className="w-full md:w-1/2 h-[45vh] md:h-full relative bg-gradient-to-b from-black/40 to-transparent p-4 flex flex-col">
          <div className="flex-1 relative">
            <AtomVisualizer element={element} mode={visualMode} color={color} />
          </div>

          {/* Mode Toggle */}
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex gap-2 bg-black/60 p-1 rounded-full border border-white/10 backdrop-blur-md">
            <button
              onClick={() => setVisualMode('bohr')}
              className={`px-4 py-2 rounded-full text-sm font-medium transition-all flex items-center gap-2 ${visualMode === 'bohr' ? 'bg-white text-black' : 'text-white/70 hover:text-white'}`}
            >
              <Atom size={16} />
              Bohr
            </button>
            <button
              onClick={() => setVisualMode('cloud')}
              className={`px-4 py-2 rounded-full text-sm font-medium transition-all flex items-center gap-2 ${visualMode === 'cloud' ? 'bg-white text-black' : 'text-white/70 hover:text-white'}`}
            >
              <Activity size={16} />
              Cloud
            </button>
          </div>
        </div>

        {/* Right: Data Scroll Area */}
        <div className="w-full md:w-1/2 h-[55vh] md:h-full overflow-y-auto bg-black/20 p-6 relative">
          <button 
            onClick={onClose} 
            className="absolute top-6 right-6 hidden md:block hover:bg-white/10 p-2 rounded-full transition-colors"
          >
            <X size={24} className="text-white/70" />
          </button>

          {/* Header */}
          <div className="mb-8">
            <div className="flex items-baseline gap-4 mb-2">
              <h1 className="text-6xl font-bold text-white tracking-tighter">{element.symbol}</h1>
              <div className="flex flex-col">
                 <span className="text-2xl font-light text-white/90">
                   {lang === 'en' ? element.name_en : element.name_cn}
                 </span>
                 {lang === 'zh' && <span className="text-sm text-white/50">{element.pinyin}</span>}
              </div>
            </div>
            <div className="flex gap-3 text-sm font-mono text-white/60">
              <span className="px-2 py-0.5 border border-white/20 rounded">No. {element.number}</span>
              <span className="px-2 py-0.5 border border-white/20 rounded">{element.atomic_mass.toFixed(3)} u</span>
              <span className="px-2 py-0.5 rounded text-black font-bold" style={{ backgroundColor: color }}>
                {element.category.replace(/-/g, ' ')}
              </span>
            </div>
          </div>

          {/* Config & Structure */}
          <section className="mb-8 grid grid-cols-2 gap-4">
             <div className="bg-white/5 p-4 rounded-xl border border-white/5">
                <h3 className="text-xs uppercase tracking-widest text-white/40 mb-2 flex items-center gap-2">
                  <Layers size={12} /> {lang === 'en' ? 'Electron Config' : '电子排布'}
                </h3>
                <code className="text-lg text-emerald-400 font-mono">{element.electron_configuration}</code>
                <div className="mt-2 text-xs text-white/50">
                  Shells: {element.shells.join(', ')}
                </div>
             </div>
             <div className="bg-white/5 p-4 rounded-xl border border-white/5">
                <h3 className="text-xs uppercase tracking-widest text-white/40 mb-2">
                   {lang === 'en' ? 'Oxidation' : '氧化态'}
                </h3>
                <div className="text-lg">
                   {/* Mock data for demo if not in main object */}
                   +1, -1
                </div>
                <div className="mt-2 text-xs text-white/50">
                  Electronegativity: {element.electronegativity || '?'}
                </div>
             </div>
          </section>

          {/* Charts (Physical Properties) */}
          <section className="mb-8 bg-white/5 p-4 rounded-xl border border-white/5">
             <h3 className="text-xs uppercase tracking-widest text-white/40 mb-4">
               {lang === 'en' ? 'Physical Properties' : '物理性质'}
             </h3>
             <div className="grid grid-cols-2 gap-4">
                <DensityChart element={element} color={color} lang={lang} />
                <TempChart element={element} color={color} lang={lang} />
             </div>
          </section>

          {/* History & Story */}
          <section className="mb-8">
             <h3 className="text-xs uppercase tracking-widest text-white/40 mb-3 flex items-center gap-2">
               <BookOpen size={12} /> {lang === 'en' ? 'History & Story' : '历史背景'}
             </h3>
             <p className="text-white/80 leading-relaxed text-sm mb-4">
               {lang === 'en' ? element.summary_en : element.summary_cn}
             </p>
             <div className="text-xs text-white/50 grid grid-cols-2 gap-4">
                <div>
                  <span className="block text-white/30">Discovered By</span>
                  {element.discoverer || 'Unknown'}
                </div>
                <div>
                  <span className="block text-white/30">Year</span>
                  {element.discovery_year || 'Ancient'}
                </div>
             </div>
          </section>

          {/* Usage & Safety */}
          <section className="grid md:grid-cols-2 gap-4 mb-8">
             <div className="bg-emerald-500/10 p-4 rounded-xl border border-emerald-500/20">
                <h3 className="text-xs uppercase tracking-widest text-emerald-400 mb-2">
                   {lang === 'en' ? 'Application' : '应用'}
                </h3>
                <p className="text-sm text-white/80">
                   {lang === 'en' ? element.usage_en : element.usage_cn}
                </p>
             </div>
             {element.hazard_en && (
               <div className="bg-rose-500/10 p-4 rounded-xl border border-rose-500/20">
                  <h3 className="text-xs uppercase tracking-widest text-rose-400 mb-2 flex items-center gap-2">
                     <AlertTriangle size={12} /> {lang === 'en' ? 'Hazard' : '危险性'}
                  </h3>
                  <p className="text-sm text-white/80">
                     {lang === 'en' ? element.hazard_en : element.hazard_cn}
                  </p>
               </div>
             )}
          </section>

        </div>
      </div>
    </div>
  );
};

export default ElementDetail;

import React, { useState } from 'react';
import { ElementData, Language } from './types';
import PeriodicTable from './components/PeriodicTable';
import ElementDetail from './components/ElementDetail';
import { Search, Globe, Box } from 'lucide-react';
import { ELEMENTS } from './data/elementData';

const App: React.FC = () => {
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);
  const [lang, setLang] = useState<Language>('zh');
  const [searchQuery, setSearchQuery] = useState('');

  // Search Logic
  const filteredElements = searchQuery 
    ? ELEMENTS.filter(e => 
        e.name_en.toLowerCase().includes(searchQuery.toLowerCase()) ||
        e.name_cn.includes(searchQuery) ||
        e.symbol.toLowerCase().includes(searchQuery.toLowerCase()) ||
        e.number.toString() === searchQuery
      )
    : [];

  const handleSearchSelect = (e: ElementData) => {
    setSelectedElement(e);
    setSearchQuery('');
  };

  return (
    <div className="min-h-screen bg-[#0f172a] text-white font-sans selection:bg-emerald-500/30">

      {/* Navbar / Header */}
      <header className="fixed top-0 left-0 right-0 z-40 bg-[#0f172a]/80 backdrop-blur-lg border-b border-white/5 h-16 flex items-center justify-between px-4 md:px-8">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-gradient-to-tr from-emerald-400 to-blue-500 rounded-lg flex items-center justify-center shadow-[0_0_15px_rgba(52,211,153,0.5)]">
            <Box size={20} className="text-black" />
          </div>
          <span className="font-bold text-xl tracking-tight hidden md:block">
            {lang === 'en' ? 'Elemental Vision' : '元素视界'}
          </span>
        </div>

        {/* Search Bar */}
        <div className="relative max-w-md w-full mx-4">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-white/40" size={18} />
            <input 
              type="text" 
              placeholder={lang === 'en' ? "Search element, symbol, number..." : "搜索元素、符号、序号..."}
              className="w-full bg-white/5 border border-white/10 rounded-full py-2 pl-10 pr-4 focus:outline-none focus:border-emerald-500/50 focus:bg-white/10 transition-all text-sm"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>

          {/* Search Dropdown */}
          {searchQuery && (
            <div className="absolute top-full mt-2 left-0 right-0 bg-[#1e293b] border border-white/10 rounded-xl shadow-2xl max-h-60 overflow-y-auto z-50">
              {filteredElements.length > 0 ? (
                filteredElements.map(e => (
                  <button 
                    key={e.number}
                    onClick={() => handleSearchSelect(e)}
                    className="w-full text-left px-4 py-3 hover:bg-white/5 flex items-center justify-between border-b border-white/5 last:border-0"
                  >
                    <div>
                      <span className="font-bold text-emerald-400 w-8 inline-block">{e.symbol}</span>
                      <span className="text-white/80">{lang === 'en' ? e.name_en : e.name_cn}</span>
                    </div>
                    <span className="text-xs text-white/30">#{e.number}</span>
                  </button>
                ))
              ) : (
                <div className="p-4 text-center text-white/40 text-sm">No results found</div>
              )}
            </div>
          )}
        </div>

        {/* Language Toggle */}
        <button 
          onClick={() => setLang(prev => prev === 'en' ? 'zh' : 'en')}
          className="flex items-center gap-2 px-3 py-1.5 rounded-full hover:bg-white/5 border border-transparent hover:border-white/10 transition-all text-sm"
        >
          <Globe size={16} />
          <span className="uppercase">{lang}</span>
        </button>
      </header>

      {/* Main Content */}
      <main className="pt-24 pb-12 px-4 md:px-8">
        <div className="text-center mb-8 md:mb-12">
          <h2 className="text-3xl md:text-5xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-emerald-300 via-teal-200 to-blue-300 mb-4">
             {lang === 'en' ? 'See the Unseen' : '看见不可见'}
          </h2>
          <p className="text-white/50 max-w-xl mx-auto text-sm md:text-base">
            {lang === 'en' 
              ? 'Explore the building blocks of the universe with immersive 3D visualization and real-time data.' 
              : '通过沉浸式 3D 可视化和实时数据，探索构成宇宙的基石。'}
          </p>
        </div>

        <PeriodicTable onSelect={setSelectedElement} />
      </main>

      {/* Detail Modal */}
      {selectedElement && (
        <ElementDetail 
          element={selectedElement} 
          onClose={() => setSelectedElement(null)} 
          lang={lang} 
        />
      )}
    </div>
  );
};

export default App;

